<template>
    <section>
        <div>
            <loader :is-visible="isLoading"></loader>
            <LeftColumn />

            <div class="right-content">

                <tg-list :IsShowAction="false" :showCheckBox="true" ModuleName="CompanySetup"
                    SubModuleCode="TemplateMapping" IdentityColumn="EVENT_MAPPING_ID" :ListData="TemplateMappingData"
                    :HeaderData="Headers" :HeaderButtons="Buttons" :TotalRecords="TotalRecords"
                    :IsSearchFieldsOnTop="false" :RenderRowActionMethod="renderActions" SearchPosition="top"
                    :SearchFields="topsearchField" :ListDataCallBackFunction="FetchData"
                    v-on:LeftsearchButtonClick="leftCommonSearch" :IsFilterApplied="searchCondition ? true : false"
                    :LegendArray="[]" sourcetype="" v-on:PagerButtonClick="pagerMethod"
                    v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata"
                    :NorecordfoundText="$t('NoRecordfound')">

                    <template v-slot:slotdata="{ data }">
                        <template v-if="data.column.COLUMN_NAME == 'STATUS_NAME'">
                            <ListingStatus v-if="StatusListForListing.length > 0" :isfor="'Template_Mapping'"
                                v-bind:dataid="data.row.EVENT_MAPPING_ID" data-controller="EmailTemplate"
                                v-bind:statuslist="StatusListForListing" v-bind:item="data" data-action="Index"
                                v-bind:dataselected="data.row.STATUS_NAME" v-bind:callbackfunction="FetchData"
                                v-bind:isselectedvaluestring="true">
                            </ListingStatus>

                        </template>

                    </template>
                </tg-list>
            </div>
        </div>


        <AddTemplateMapping v-if="showAddPopup" :EventMappingId = "EventMappingId" v-on:closepopup="showAddPopup = false;" />

    </section>
</template>
<script>
import LeftColumn from "../Company/LeftColumn.vue";
import DataService from "@/services/DataService";
import AddTemplateMapping from "../../components/Modals/AddTemplateMapping.vue";
import ListingStatus from "../../components/Common/Listing.vue";

export default {
    components: {
        LeftColumn,
        AddTemplateMapping,
        ListingStatus
    },

    data() {
        return {
            isLoading: false,
            pageSize: 10,
            pageNum: 1,
            sortBy: null,
            sortExp: null,
            TotalRecords: null,
            TotalPages: 0,
            TemplateMappingData: [],
            searchCondition: '',
            Headers: [
                {
                    COLUMN_NAME: "TEMPLATE_NAME",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "Template Name",
                    DISPLAY_ORDER: 1,
                }, {
                    COLUMN_NAME: "EVENT_NAME",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "Event Type",
                    DISPLAY_ORDER: 2,
                }, {
                    COLUMN_NAME: "STATUS_NAME",
                    DATA_TYPE: "text",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: "Status",
                    DISPLAY_ORDER: 3,
                }

            ],
            Buttons: [
                {
                    title: this.$t('Add'),
                    iconClass: 'fa-plus',
                    callbackfunction: 'AddScreenPopup',
                    additionalClass: '',
                    isdisabled: false,
                    isvisible: true,
                    checkPrivilege: true
                }, {
                    id: 'ActiveMultiple',
                    title: this.$t('Active'),
                    iconClass: 'fa-check',
                    callbackfunction: 'ActiveMultipleListing',
                    additionalClass: '',
                    isdisabled: true,
                    isvisible: true,
                    checkPrivilege: true,
                    isEnabledOnSelectedRow: true
                }, {
                    id: 'InactiveMultiple',
                    title: this.$t('Inactive'),
                    iconClass: 'fa-close',
                    callbackfunction: 'InactiveMultipleListing',
                    additionalClass: '',
                    isdisabled: true,
                    isvisible: true,
                    checkPrivilege: true,
                    isEnabledOnSelectedRow: true
                }, {
                    id: 'DeleteMultiple',
                    title: this.$t('Delete'),
                    iconClass: 'fa-trash-o',
                    callbackfunction: 'commonDeleteData',
                    isdisabled: true,
                    isvisible: true,
                    isEnabledOnSelectedRow: true
                }
            ],
            topsearchField: [
                {
                    fieldName: 'Template Name  ',
                    fieldType: "text",
                    // fieldIcon: "fa-file",
                    //fieldSearchConditionName: '',
                    paramName: "SEARCH",
                    fieldSearchConditionName: ['SEARCH'],
                    isSearch: true,
                    value: "",
                    listOptions: []
                },
            ],
            showAddPopup: false,
            StatusListForListing: [],
            EventMappingId: null,
        }
    },
    mounted() {
        var ths = this;
        ths.topsearchField.forEach(item => {
            item.value = '';
            item.isSearch = false;
        })
    },
    async created() {

        //this.userTypeId = this.GetUserInfo.UserType == 'CA' ? 1 : this.GetUserInfo.UserType == 'PM' ? 2 : this.GetUserInfo.UserType == 'NU' ? 3 : 4;
        var vm = this;
        vm.FetchData();
        vm.getStatuslistForListing("Dynamic_Reporting", "en");


    },

    methods: {
        clickEventOfColumn: function (row, column) {
            debugger
            if (column.COLUMN_NAME == 'TEMPLATE_NAME') {
                this.EventMappingId = row.EVENT_MAPPING_ID;
                this.showAddPopup = true;
            }
        },
        FetchData: async function () {
            debugger
            var vm = this;

            var url = `search=${vm.searchCondition}&status=&pageSize=${vm.pageSize}&pageNum=${vm.pageNum}&sortBy=${vm.sortBy}&sortExp=${vm.sortExp}`;
            await DataService.GetTemplateMappingList(url).then((response) => {
                if (response.data) {

                    vm.Headers.forEach((column) => {
                        column.settings = null;
                        if (column.COLUMN_NAME == "TEMPLATE_NAME") {
                            column.settings = {
                                clickEvent: vm.clickEventOfColumn,
                                formatter: vm.columnDataFormatter,
                            };
                        }

                    });
                    vm.TemplateMappingData = response.data.result.map(item => {
                        return {
                            ...item,
                            EVENT_NAME: vm.$t(item.EVENT_NAME) // translate here
                        };
                    });

                    vm.TotalRecords = vm.TemplateMappingData[0].TOTALRECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.pageSize);
                    vm.CurrentPage = vm.pageNum;

                    vm.Headers.forEach((column) => {
                        column.DISPLAY_NAME = vm.$t(column.DISPLAY_NAME);
                        if (column.COLUMN_NAME == "STATUS_NAME") {
                            column.settings = {
                                isInSlot: true
                            };
                        }
                    });
                }


            });
        },
        renderActions: function (row) {

            return [];
        },
        leftCommonSearch: async function (value) {

            var vm = this;

            this.pageNum = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {

                //this.searchCondition = value.searchCondition;
                this.searchCondition = value.searchConditionJson.replace('SEARCH=', '');
            }
            else {
                this.searchCondition = "";
            }

            await this.FetchData();
        },
        pagerMethod: async function (value) {
            this.pageSize = value.PageSize;
            this.pageNum = value.PageNumber;
            await this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "commonDeleteData":
                    this.DeleteTemplate();
                    break;

                case "ActiveMultipleListing":

                    this.ActiveTemplate();
                    break;

                case "InactiveMultipleListing":

                    this.InactiveTemplate();
                    break;

                case "AddScreenPopup":
                    this.EventMappingId = null;
                    this.showAddPopup = true;
                    break;
            }
        },
        sortdata: async function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.sortBy = s;
            if (s === this.sortBy) {
                if (this.sortExp == "") {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.sortExp == "ASC") {
                    this.sortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }

            await this.FetchData();
            $("#th-" + s + '  span:first-child').attr("class", SortDir);
        },

        ActiveTemplate: async function () {

            var vm = this;

            var val = "";

            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });

            var url = `Id=${val}&Status=1001`;

            await DataService.ActiveTemplate(url).then((response) => {
                if (response.data.status == "Success") {

                    vm.ShowAlert(vm.$t("TemplateStatus"), "success", vm.$t('Alert'));
                    vm.FetchData();

                }
                else {

                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }

            });
        },

        InactiveTemplate: async function () {

            var vm = this;

            var val = "";

            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });

            var url = `Id=${val}&Status=1002`;

            await DataService.InactiveTemplate(url).then((response) => {
                if (response.data.status == "Success") {

                    vm.ShowAlert(vm.$t("TemplateStatus"), "success", vm.$t('Alert'));
                    vm.FetchData();

                }
                else {

                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }


            });
        },

        DeleteTemplate: async function () {

            var vm = this;

            var val = "";

            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });

            var url = `Id=${val}`;

            await DataService.DeleteTemplate(url).then((response) => {
                if (response.data.status == "Success") {
                    vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('TemplateMapping')]), "success", true, vm.$t("Alert"));
                    //vm.ShowAlert(vm.$t("TemplateMappingDelete"), "success", vm.$t('Alert'));
                    vm.FetchData();

                }
                else {

                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }


            });
        },

        getStatuslistForListing: function (StatusType, lang) {

            var vm = this;
            var url = "langCode=" + lang + "&statusType=" + StatusType + "&hasglobal=true";
            DataService.statusdropdown(url).then(function (response) {
                if (response.data.status == "Success") {
                    var json = response.data.result;
                    vm.StatusListForListing = json.data;
                }
            });
        }
    }
}
</script>
