<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div>
            <div class="my-popups">
                <div class="modal d-block ">
                    <div class="modal-dialog ui-draggable" style="display: inline-block;">
                        <div class="modal-content">
                            <div class="modal-header ui-draggable-handle">
                                <h5 id="ui-id-26" class="modal-title">Manage Template Mapping</h5>
                                <button type="button" title="" class="close" @click="Close"
                                    data-original-title="Close"><i class="fa fa-times" aria-hidden="true"></i></button>
                                <!-- <span class="user-guide ">
                                    <a class="ancuserguide" data-toggle="collapse" href="javascript:;" role="button"
                                        aria-expanded="false" style="color: white;" aria-controls="collapseExample"> <em
                                            class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                                    <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                        <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                            <div class="con" v-html="getUserGuideTitle($t(addUserGuide))"></div>
                                        </div>
                                    </div>
                                </span> -->
                            </div>
                            <div id="backgroundPopup" class="modal-body"
                                style="height: auto; min-height: 0px; max-height: none;">
                                <dynamic-form ref="dynamicform" lang="en" :buttons="buttons" :schema="FormSchema"
                                    v-on:OnSubmit="onSubmit" :mandatorytext="$t('MandatoryString')">


                                </dynamic-form>
                            </div>
                        </div>
                    </div>
                </div>

            </div>

        </div>
    </section>
</template>


<script>

import DataService from "../../services/DataService";

export default {


    data() {
        return {
            isLoading: false,
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                    astype: "SelectField",
                    label: this.$t('Template Name'),
                    name: "TemplateName",
                    value: "",
                    visibility: true,
                    config: {
                        options: [],
                        //onChange: this.onActivityIdChange
                    },
                    validationRules: {
                        required: true
                    },
                    disabled: false
                },
                {
                    astype: "SelectField",
                    label: this.$t('Event Type'),
                    name: "EventType",
                    value: "",
                    visibility: true,
                    config: {
                        options: [],
                        //onChange: this.onActivityIdChange
                    },
                    validationRules: {
                        required: true
                    },
                    disabled: false
                },
                {
                    astype: "SelectField",
                    label: this.$t('Status'),
                    name: "Status",
                    value: "",
                    visibility: true,
                    config: {
                        options: [],
                        //onChange: this.onActivityIdChange
                    },
                    validationRules: {
                        required: true
                    },
                    disabled: false
                }
                ],
            },
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
            TemplateNameData: [],

        }
    },
    props: {
        EventMappingId: {
            type: Number,
            default: null
        }
    },
    async created() {
        debugger

        var vm = this;
        vm.FetchTemplateData();
        vm.FetchEventData();
        vm.FetchStatusData();
        vm.UpdateEventMapping();
    },

    methods: {

        UpdateEventMapping: async function () {
            debugger
            var vm = this;
            if (vm.EventMappingId == null || vm.EventMappingId == undefined) {
                return;
            }

            var url = `EventMappingId=${vm.EventMappingId}`;

            await DataService.UpdateEventMapping(url).then((response) => {
                if (response.data.status == "Success") {

                    let resultStr = response.data.result;

                    // 1️⃣ Convert string → JSON object
                    let parsedResult = JSON.parse(resultStr);

                    // 2️⃣ Get first item from Data array
                    let dataObj = parsedResult.Data[0];

                    // 3️⃣ Extract values into separate variables
                    let event_mapping_id = dataObj.event_mapping_id;
                    let template_id = dataObj.template_id;
                    let event_id = dataObj.event_id;
                    let status_id = dataObj.status_id;

                    vm.$refs.dynamicform.updateProperty("TemplateName", "value", template_id);
                    vm.$refs.dynamicform.updateProperty("EventType", "value", event_id);
                    vm.$refs.dynamicform.updateProperty("Status", "value", status_id);
                }
                else {

                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }

            });
        },

        FetchTemplateData: async function () {

            var vm = this;
            let selctedValue = [];

            await DataService.GetTemplateList().then((response) => {
                if (response.data) {

                    var json = response.data.result;
                    if (json != null) {
                        json.forEach(item => {
                            let obj = {
                                name: item.template_name,
                                value: item.template_id
                            };
                            selctedValue.push(obj);
                        });
                        vm.$refs.dynamicform.updateProperty("TemplateName", "config.options", selctedValue);
                        vm.$refs.dynamicform.UpdateKeyValue();
                    }
                }


            });
        },

        FetchEventData: async function () {

            var vm = this;
            let selctedValue = [];

            await DataService.GetEventList().then((response) => {
                if (response.data) {

                    var json = response.data.result;
                    if (json != null) {
                        json.forEach(item => {
                            let obj = {
                                name: vm.$t(item.event_name),
                                value: item.event_id
                            };
                            selctedValue.push(obj);
                        });
                        vm.$refs.dynamicform.updateProperty("EventType", "config.options", selctedValue);
                        vm.$refs.dynamicform.UpdateKeyValue();
                    }
                }


            });
        },

        FetchStatusData: async function () {
            debugger
            var vm = this;
            let selctedValue = [];

            await DataService.GetStatusList().then((response) => {
                if (response.data) {

                    var json = response.data.result;
                    if (json != null) {
                        json.forEach(item => {
                            let obj = {
                                name: item.STATUS,
                                value: item.STATUS_ID
                            };
                            selctedValue.push(obj);
                        });
                        vm.$refs.dynamicform.updateProperty("Status", "config.options", selctedValue);
                        vm.$refs.dynamicform.UpdateKeyValue();
                    }
                }


            });
        },

        onSubmit: async function () {
            debugger
            var vm = this;

            var Templatevalue = vm.$refs.dynamicform.getPropertyValue("TemplateName", "value") || '';
            var EventValue = vm.$refs.dynamicform.getPropertyValue("EventType", "value") || '';
            var StatusValue = vm.$refs.dynamicform.getPropertyValue("Status", "value") || '';

            var url = `Templatevalue=${Templatevalue}&EventValue=${EventValue}&StatusValue=${StatusValue}&EventMappingId=${vm.EventMappingId}`;

            await DataService.SaveData(url).then((response) => {
                if (response.data.status == "Success") {

                    if (response.data.result == 0) {
                        vm.ShowAlert(vm.$t("TemplateAdd"), "success", vm.$t('Alert'));

                    }
                    else {
                        vm.ShowAlert(vm.$t("UpdateEmail"), "success", vm.$t('Alert'));

                    }
                    this.$parent.showAddPopup = false;
                    this.$parent.FetchData();

                }
                else if (response.data.status == "Failure") {

                    vm.ShowAlert(vm.$t("TemplateExists"), "failure", vm.$t('Alert'));
                }
                else {

                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }

            });
        },
        Close: function () {
            this.$parent.showAddPopup = false;

        }
    }
}
</script>

